Example:
// Using injectable for auto-registration
@InjectableInit(preferRelativeImports: true)
void configureDependencies() => getIt.init();

// Module for third-party registrations
@module
abstract class RegisterModule {
  @lazySingleton
  Dio get dio => Dio(BaseOptions(baseUrl: AppConfig.baseUrl))
    ..interceptors.addAll([AuthInterceptor(getIt()), LogInterceptor()]);

  @lazySingleton
  SharedPreferences get prefs => getIt<SharedPreferences>();
}

// Pre-resolve async singletons
@preResolve
@lazySingleton
Future<SharedPreferences> get prefs => SharedPreferences.getInstance();

